max_new_tokens= 32 ,
do_sample= False ,
new_tokens = generated[:, inputs.input_ids.shape[ 1 ]:]
response = processor.batch_decode(new_tokens, skip_special_tokens= True )[ 0 ].strip()
print (response) # e.g. [512,384]
